    28→type MetricStreamingDecoder struct {
    29→	in    []byte
    30→	inPos int
    31→
    32→	// TODO(bwplotka): Switch to generator/plugin that won't have those fields accessible e.g. OpaqueAPI
    33→	// We leverage the fact those two don't collide.
    34→	*MetricFamily // Without Metric, guarded by overridden GetMetric method.
    35→	*Metric       // Without Label, guarded by overridden GetLabel method.
    36→
    37→	mfData      []byte
    38→	metrics     []pos
    39→	metricIndex int
    40→
    41→	mData  []byte
    42→	labels []pos
    43→}
    44→
    45→// NewMetricStreamingDecoder returns a Go iterator that unmarshals given protobuf bytes one
    46→// metric family and metric at the time, allowing efficient streaming.
    47→//
    48→// Do not modify MetricStreamingDecoder between iterations as it's reused to save allocations.
    49→// GetGauge, GetCounter, etc are also cached, which means GetGauge will work for counter
    50→// if previously gauge was parsed. It's up to the caller to use Type to decide what
    51→// method to use when checking the value.
    52→//
    53→// TODO(bwplotka): io.Reader approach is possible too, but textparse has access to whole scrape for now.
    54→func NewMetricStreamingDecoder(data []byte) *MetricStreamingDecoder {
    55→	return &MetricStreamingDecoder{
    56→		in:           data,
    57→		MetricFamily: &MetricFamily{},
    58→		Metric:       &Metric{},
    59→		metrics:      make([]pos, 0, 100),
    60→	}
    61→}
    62→
    63→var errInvalidVarint = errors.New("clientpb: invalid varint encountered")
    64→
    65→// NextMetricFamily decodes the next metric family from the input without metrics.
    66→// Use NextMetric() to decode metrics. The MetricFamily fields Name, Help and Unit
    67→// are only valid until NextMetricFamily is called again.
    68→func (m *MetricStreamingDecoder) NextMetricFamily() error {
    69→	b := m.in[m.inPos:]
    70→	if len(b) == 0 {
    71→		return io.EOF
    72→	}
    73→	messageLength, varIntLength := proto.DecodeVarint(b) // TODO(bwplotka): Get rid of gogo.
    74→	if varIntLength == 0 || varIntLength > binary.MaxVarintLen32 {
    75→		return errInvalidVarint
    76→	}
    77→	totalLength := varIntLength + int(messageLength)
    78→	if totalLength > len(b) {
    79→		return fmt.Errorf("clientpb: insufficient length of buffer, expected at least %d bytes, got %d bytes", totalLength, len(b))
    80→	}
    81→	m.resetMetricFamily()
    82→	m.mfData = b[varIntLength:totalLength]
    83→
    84→	m.inPos += totalLength
    85→	return m.unmarshalWithoutMetrics(m, m.mfData)
    86→}
